import{_ as a,o as t,c as i,ag as o}from"./chunks/framework.CnqOxlWO.js";const p=JSON.parse('{"title":"Login & Registration","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/login.md","filePath":"getting-started/login.md","lastUpdated":1773376681000}'),n={name:"getting-started/login.md"};function l(r,e,s,h,c,d){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="login-registration" tabindex="-1">Login &amp; Registration <a class="header-anchor" href="#login-registration" aria-label="Permalink to &quot;Login &amp; Registration&quot;">​</a></h1><p>ClawdSaber uses <strong>email magic links</strong> for authentication. There are no passwords to remember — just enter your email, click the link, and you are in.</p><p>If your email is not yet registered, an account is created automatically on first login.</p><h2 id="how-to-log-in" tabindex="-1">How to Log In <a class="header-anchor" href="#how-to-log-in" aria-label="Permalink to &quot;How to Log In&quot;">​</a></h2><ol><li>Open ClawdSaber.</li><li>Enter your email address on the login screen.</li><li>Click <strong>Send Magic Link</strong>.</li><li>The screen changes to a &quot;waiting for email&quot; state.</li><li>Check your inbox and click the link.</li></ol><h2 id="two-ways-to-complete-login" tabindex="-1">Two Ways to Complete Login <a class="header-anchor" href="#two-ways-to-complete-login" aria-label="Permalink to &quot;Two Ways to Complete Login&quot;">​</a></h2><h3 id="method-a-click-the-link-directly" tabindex="-1">Method A: Click the Link Directly <a class="header-anchor" href="#method-a-click-the-link-directly" aria-label="Permalink to &quot;Method A: Click the Link Directly&quot;">​</a></h3><p>If your system supports deep links, clicking the link in the email opens ClawdSaber automatically and completes login.</p><p>The deep link uses the <code>clawsaber://</code> protocol. If your OS prompts you to allow it, confirm to proceed.</p><h3 id="method-b-copy-and-paste" tabindex="-1">Method B: Copy and Paste <a class="header-anchor" href="#method-b-copy-and-paste" aria-label="Permalink to &quot;Method B: Copy and Paste&quot;">​</a></h3><p>If clicking the link opens a browser page instead:</p><ol><li>Copy the full URL from the email.</li><li>Switch back to ClawdSaber.</li><li>Paste the URL into the input field shown on the waiting screen.</li><li>Click <strong>Verify</strong>.</li></ol><h2 id="what-happens-after-login" tabindex="-1">What Happens After Login <a class="header-anchor" href="#what-happens-after-login" aria-label="Permalink to &quot;What Happens After Login&quot;">​</a></h2><ul><li><strong>First-time user</strong>: The setup wizard appears. See <a href="/clawdsaber-docs/getting-started/quickstart.html">Quick Start</a>.</li><li><strong>Returning user</strong>: You go directly to the chat page.</li></ul><h2 id="language-selection" tabindex="-1">Language Selection <a class="header-anchor" href="#language-selection" aria-label="Permalink to &quot;Language Selection&quot;">​</a></h2><p>The login page has a language selector in the top-right corner. Three languages are supported:</p><ul><li>English</li><li>Chinese</li><li>Japanese</li></ul><p>You can also change the language later in <a href="/clawdsaber-docs/settings/overview.html">Settings</a>.</p><h2 id="common-issues" tabindex="-1">Common Issues <a class="header-anchor" href="#common-issues" aria-label="Permalink to &quot;Common Issues&quot;">​</a></h2><h3 id="i-did-not-receive-the-email" tabindex="-1">I did not receive the email <a class="header-anchor" href="#i-did-not-receive-the-email" aria-label="Permalink to &quot;I did not receive the email&quot;">​</a></h3><ul><li>Check your spam or junk folder.</li><li>Make sure you entered the correct email address.</li><li>Wait a moment and try again — sometimes delivery takes a minute.</li></ul><h3 id="the-link-does-not-open-the-app" tabindex="-1">The link does not open the app <a class="header-anchor" href="#the-link-does-not-open-the-app" aria-label="Permalink to &quot;The link does not open the app&quot;">​</a></h3><ul><li>Copy the full URL and paste it into the app manually (Method B).</li><li>Make sure ClawdSaber is still running when you click the link.</li></ul><h3 id="the-link-expired" tabindex="-1">The link expired <a class="header-anchor" href="#the-link-expired" aria-label="Permalink to &quot;The link expired&quot;">​</a></h3><p>Magic links are valid for a limited time. If the link has expired, go back to the login screen and request a new one.</p><h3 id="i-am-stuck-on-the-login-screen-after-clicking-the-link" tabindex="-1">I am stuck on the login screen after clicking the link <a class="header-anchor" href="#i-am-stuck-on-the-login-screen-after-clicking-the-link" aria-label="Permalink to &quot;I am stuck on the login screen after clicking the link&quot;">​</a></h3><ul><li>Try copying and pasting the link instead.</li><li>Restart ClawdSaber and request a fresh magic link.</li></ul>',27)])])}const u=a(n,[["render",l]]);export{p as __pageData,u as default};
